def compute_score() -> tuple[str, float]:
    from pptx import Presentation
    def get_image_shapes(slide):
        images = []
        for shape in slide.shapes:
            if shape.is_placeholder and shape.placeholder_format.type == 7:
                images.append(shape)

            if shape.shape_type == 13:  # Picture
                images.append(shape)
        return images

    mod = Presentation(modified_ppt_path)
    try:
        mod_slide = mod.slides[3]
    except IndexError:
        return "Slide 4 missing in modified file.", 0.0
    mod_imgs = get_image_shapes(mod_slide)
    if len(mod_imgs) != 1:
        return f"Expected exactly 1 image, found {len(mod_imgs)}.", 0.0

    rot = mod_imgs[0].rotation
    diff = abs(rot - 90)
    # Full credit
    if diff <= 5:
        return "Image was rotated as expected.", 1.0
    # Partial credit for near correct
    elif 5 < diff < 15:
        return f"Image rotation is close to expected (Rotation: {rot}).", 0.7
    # Special case: 40-50 degrees
    elif 40 <= rot <= 50:
        return f"Image rotation is between 40 and 50 degrees (Rotation: {rot}).", 0.5
    # More than 15 degrees clockwise
    elif 15 <= rot < 40:
        return f"Image rotation is more than 15 degrees clockwise (Rotation: {rot}).", 0.25
    elif 0 < rot < 15:
        return f"Image rotation is less than 15 degrees clockwise (Rotation: {rot}).", 0.1
    # Otherwise, no credit
    return f"Image was not rotated properly. Rotation: {rot}", 0.0

def compute_score() -> tuple[str, float]:
    # Compare element rotation/position for all slides except 4
    from pptx import Presentation
    orig = Presentation(original_ppt_path)
    mod = Presentation(modified_ppt_path)
    for i, (os, ms) in enumerate(zip(orig.slides, mod.slides), start=1):
        if i == 4:
            continue
        if len(os.shapes) != len(ms.shapes):
            return (f"Number of shapes differs on slide {i}.", 0.0)
        # Check rotation for each shape
        for osh, msh in zip(os.shapes, ms.shapes):
            # Only check if both have .rotation (not all shapes do)
            rot_o = getattr(osh, 'rotation', None)
            rot_m = getattr(msh, 'rotation', None)
            if rot_o is not None and rot_m is not None:
                # Allow a very tiny difference (1 degree)
                if abs(rot_o - rot_m) > 1:
                    return (f"Shape on slide {i} was rotated/modified.", 0.0)
    return ("No unintended rotation/modification found on non-target slides.", 1.0)

def compute_score() -> tuple[str, float]:
    # Compare slide count and order
    orig_slides = [s.slide_number for s in original_ppt_screenshots]
    mod_slides = [s.slide_number for s in modified_ppt_screenshots]
    if len(orig_slides) != len(mod_slides):
        return ("Number of slides changed.", 0.0)
    for i, (o, m) in enumerate(zip(orig_slides, mod_slides)):
        if o != m:
            return ("Slide order changed.", 0.0)
    # Check diff for slides added/removed
    if ppt_diff.added_slides or ppt_diff.removed_slides:
        return ("Slides were added or removed.", 0.0)
    return ("No extraneous slide changes detected.", 1.0)

def compute_score() -> tuple[str, float]:
    # Use pptx to check for new/removed shapes on slide 4
    from pptx import Presentation
    orig = Presentation(original_ppt_path)
    mod = Presentation(modified_ppt_path)
    try:
        os = orig.slides[3]  # 0-indexed
        ms = mod.slides[3]
    except IndexError:
        return ("Slide 4 missing in one of the files.", 0.0)
    if len(os.shapes) != len(ms.shapes):
        return ("Number of shapes on slide 4 changed.", 0.0)
    # Optionally, check text in shapes
    orig_texts = [sh.text for sh in os.shapes if hasattr(sh, 'text')]
    mod_texts = [sh.text for sh in ms.shapes if hasattr(sh, 'text')]
    if orig_texts != mod_texts:
        return ("Text content on slide 4 changed.", 0.0)
    return ("No content changes except diagram rotation on slide 4.", 1.0)

def compute_score() -> tuple[str, float]:
    # Use VLM to compare for style/formatting changes
    orig_img = None
    mod_img = None
    for s in original_ppt_screenshots:
        if s.slide_number == 4:
            orig_img = s.image_path
            break
    for s in modified_ppt_screenshots:
        if s.slide_number == 4:
            mod_img = s.image_path
            break
    if not orig_img or not mod_img:
        return ("Could not find screenshots for slide 4.", 1.0)  # lenient
    prompt = (
        "Compare the two images of slide 4. Aside from the diagram along with its title being rotated, did any other formatting or style (such as color, font, background, or effects) change? "
        "Answer only 'Yes' or 'No', followed by a brief explanation."
    )
    resp = vlm_call(prompt, images=[orig_img, mod_img], temperature=0)
    if 'no' in resp.lower():
        return ("No style/formatting changes except diagram rotation.", 1.0)
    elif 'yes' in resp.lower():
        return ("Formatting or style changed unexpectedly on slide 4. " + resp, 0.0)
    return ("Could not determine formatting/style change.", 0.5)
